// ═══ Configuração de Prospecção JuriAI ═══
// Fase 1: Goiânia | Fase 2: Região GO | Fase 3: Brasília | Fase 4+: Expandir
const FASES = [
  [{ city: 'Goiânia', state: 'GO' }],
  [{ city: 'Aparecida de Goiânia', state: 'GO' }, { city: 'Anápolis', state: 'GO' }],
  [{ city: 'Brasília', state: 'DF' }],
  [{ city: 'Uberlândia', state: 'MG' }, { city: 'Ribeirão Preto', state: 'SP' }],
  [{ city: 'Belo Horizonte', state: 'MG' }, { city: 'Campinas', state: 'SP' }],
];

// Semana atual desde o início (ajuste a data de início)
const START_DATE = new Date('2026-04-22');
const now = new Date();
const weekNum = Math.floor((now - START_DATE) / (7 * 24 * 60 * 60 * 1000));
const faseIdx = Math.min(weekNum, FASES.length - 1);

// Só roda seg-sex
const dayOfWeek = now.getDay();
if (dayOfWeek === 0 || dayOfWeek === 6) {
  return []; // Pula fim de semana
}

return [{
  json: {
    cities: FASES[faseIdx],
    fase: faseIdx + 1,
    minReviews: 3,
    radiusKm: 5,
    maxSends: 5,  // Warm-up: começar com 5/dia
    delayMs: 60000, // 60s entre envios
    segmentId: 'escritorios-advocacia'
  }
}];

const leads = $input.all();
const total = leads.length;
const quentes = leads.filter(l => l.json.qualification?.classificacao === 'QUENTE').length;
const mornos = leads.filter(l => l.json.qualification?.classificacao === 'MORNO').length;
const comWa = leads.filter(l => l.json.whatsapp).length;
const aiAnalyzed = leads.filter(l => l.json.qualification?.ai_analyzed).length;

return [{
  json: {
    mensagem: `⚖️ Prospecção JuriAI — Fase ${$('Config Prospecção').item.json.fase}\n\n📊 Total: ${total} leads com contato\n🔥 Quentes: ${quentes}\n🟡 Mornos: ${mornos}\n📱 Com WhatsApp: ${comWa}\n🤖 Qualificados por IA: ${aiAnalyzed}`
  }
}];

const l = $json;
const q = l.qualification || {};
const ig = typeof l.instagram === 'object' ? l.instagram : null;
const payload = {
  nome: l.nome || l.name,
  whatsapp: l.whatsapp || null,
  telefone: l.telefone || l.phone || null,
  email: l.email || null,
  endereco: l.endereco || l.address || null,
  segmento: 'escritorios-advocacia',
  source: l.source || 'prospector',
  score: Number(q.score ?? l.score ?? 0),
  classificacao: q.classificacao,
  argumento_principal: q.argumento_principal || null,
  mensagem_whatsapp: q.mensagem_whatsapp || null,
  plano_recomendado: q.plano_recomendado || null,
  tags: [...(Array.isArray(q.tags) ? q.tags : []), 'juriai', l.cidade || ''].filter(Boolean),
  external_refs: {
    place_id: l.place_id || null,
    cnpj: l.cnpj || null,
    instagram_handle: ig?.handle || (typeof l.instagram === 'string' ? l.instagram : null),
    website: l.website || null
  },
  extra: {
    rating: l.rating ?? null,
    reviews_count: l.totalAvaliacoes ?? l.reviews_count ?? l.user_ratings_total ?? null,
    cidade: l.cidade ?? null,
    perfil: q.perfil ?? null,
    dores_provaveis: q.dores_provaveis ?? null,
    ai_analyzed: q.ai_analyzed ?? false
  }
};
return [{ json: payload }];
